namespace QAHub.Api.Domain.Defects;
public sealed class BugStatusHistory { private BugStatusHistory(){} public BugStatusHistory(Guid bugId,BugStatus from,BugStatus to,string actor,string reason){Id=Guid.NewGuid();BugId=bugId;FromStatus=from;ToStatus=to;ActorId=actor.Trim();Reason=reason.Trim();ChangedAtUtc=DateTimeOffset.UtcNow;}public Guid Id{get;private set;}public Guid BugId{get;private set;}public BugStatus FromStatus{get;private set;}public BugStatus ToStatus{get;private set;}public string ActorId{get;private set;}=string.Empty;public string Reason{get;private set;}=string.Empty;public DateTimeOffset ChangedAtUtc{get;private set;} }
